def classify(text):
    if "order" in text.lower() and "cancel" in text.lower():
        return "yes"
    return "no"

regression_cases = [
    {"name": "explicit_cancel",
     "input": "please cancel my order",
     "expected": "yes"},
    {"name": "no_intent",
     "input": "what's the status of my order",
     "expected": "no"},
    {"name": "account_cancel",
     "input": "cancel my account",
     "expected": "yes"},
]

def run_suite(cases):
    passed = 0
    for c in cases:
        if classify(c["input"]).lower() == c["expected"].lower():
            passed += 1
    return passed, len(cases)

p, t = run_suite(regression_cases)
print(f"{p}/{t}")

