steps.solution:
def judge_rubric(question, answer, rubric):
    if "Paris" in answer:
        return {"passed": True,  "critique": "Names Paris."}
    return {"passed": False, "critique": "Does not name Paris."}

cases = [
    {"question": "capital of France?", "answer": "Paris.",                          "rubric": "Reward correct answer."},
    {"question": "capital of France?", "answer": "Lyon, I think.",                  "rubric": "Reward correct answer."},
    {"question": "capital of France?", "answer": "Paris, in northern France.",      "rubric": "Reward correct, concise answer."},
    {"question": "capital of France?", "answer": "Some city in the south, maybe.",  "rubric": "Reward correct answer."},
]

def run_judge_suite(cases):
    passed_count = 0
    for c in cases:
        v = judge_rubric(c["question"], c["answer"], c["rubric"])
        if v["passed"]:
            passed_count += 1
    total = len(cases)
    failed_count = total - passed_count
    pass_rate = round(passed_count / total, 2) if total else 0.0
    return {
        "total": total,
        "passed": passed_count,
        "failed": failed_count,
        "pass_rate": pass_rate,
    }

result = run_judge_suite(cases)
print(f"total={result['total']} passed={result['passed']} failed={result['failed']} pass_rate={result['pass_rate']}")
